$ErrorActionPreference  = "SilentlyContinue"
$ProgressPreference     = "SilentlyContinue"
$WarningPreference      = "SilentlyContinue"
$VerbosePreference      = "SilentlyContinue"
$ConfirmPreference      = "None"

# ============================================================
# HELPER FUNCTIONS
# ============================================================
function RegSet($path, $name, $value, $type = "DWord") {
    If (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
    Set-ItemProperty -Path $path -Name $name -Value $value -Type $type -EA SilentlyContinue
}
function SvcKill($name) {
    $s = Get-Service -Name $name -EA SilentlyContinue
    If ($s) {
        Stop-Service    $name -Force           -EA SilentlyContinue
        Set-Service     $name -StartupType Disabled -EA SilentlyContinue
        sc.exe config   $name start= disabled  2>$null | Out-Null
    }
}
function SvcEnable($name, $startType = "Automatic") {
    $s = Get-Service -Name $name -EA SilentlyContinue
    If ($s) {
        Set-Service  $name -StartupType $startType -EA SilentlyContinue
        sc.exe config $name start= auto 2>$null | Out-Null
        Start-Service $name -EA SilentlyContinue
    }
}

# ============================================================
# [A] POWER PLAN — "Final Premium V0.0.1 by Nelly Stephod"
#     .pow ถูก embed เป็น Base64 ในไฟล์นี้แล้ว — รันไฟล์เดียวจบ
# ============================================================
 
$planName = "Final Premium V0.0.1 by Nelly Stephod"
 
# ลบ plan เดิมที่ชื่อเดียวกัน (ถ้ามี)
powercfg -list 2>$null | Select-String $planName | ForEach-Object {
    $g = ($_ -split "\s+")[3]
    If ($g) { powercfg -delete $g 2>$null | Out-Null }
}
 
# Decode .pow จาก Base64 แล้ว import
$powB64  = ""
$powPath = "$env:TEMP\FinalPremium_NellyStephod.pow"
[IO.File]::WriteAllBytes($powPath, [Convert]::FromBase64String($powB64))
powercfg -import $powPath 2>$null | Out-Null
Remove-Item $powPath -EA SilentlyContinue
 
# หา GUID ที่ import มา แล้ว set active
$planGuid = ""
powercfg -list 2>$null | Select-String $planName | ForEach-Object {
    $m = [regex]::Match($_, "[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}")
    If ($m.Success) { $planGuid = $m.Value }
}
If ($planGuid) { powercfg -setactive $planGuid 2>$null | Out-Null }
 
 

