$adapters = Get-NetAdapter | Where-Object {
    $_.Status -eq "Up" -and
    $_.InterfaceDescription -notlike "*Virtual*" -and
    $_.InterfaceDescription -notlike "*Loopback*" -and
    $_.InterfaceDescription -notlike "*Bluetooth*"
}
ForEach ($a in $adapters) {
